scwin.f_Retrieve = async function () {
  let chkwrkplcd = ed_wrkPlCd.getValue();
  if ($c.gus.cfIsNull($p, chkwrkplcd)) {
    await $c.win.alert($p, "작업장 코드는 필수 입력 항목입니다.");
    ed_wrkPlCd.focus();
    return;
  }
  let chk = await $c.gus.cfValidate($p, [tb_queryList], null, true);
  // 필수항목 체크
  if (!chk) {
    return;
  }
  if (ed_mrn.getValue() == "" && ed_blNo.getValue() == "" && ed_odrNo.getValue() == "" && crryinoutDtmFrom.getValue() == "") {
    await $c.win.alert($p, "MRN,BL번호,오더번호,일자 중 하나는 입력해야 합니다.");
    return;
  } else {
    if (ed_mrn.getValue() != "") {
      if (ed_mrn.getValue().length < 11) {
        await $c.win.alert($p, "MRN은 11자리입니다");
        ed_mrn.focus();
        return;
      }
    }
  }
  if (ed_odrNo.getValue() != "") {
    if (ed_odrNo.getValue().length < 13) {
      await $c.win.alert($p, "오더번호는 13자리입니다.");
      ed_odrNo.focus();
      return;
    }
  }
  if (!$c.gus.cfIsAfterDate($p, crryinoutDtmFrom.getValue(), crryinoutDtmTo.getValue())) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
    crryinoutDtmFrom.focus();
    return;
  }
  let cheVal = "0";
  if (preRetrieve.getValue() == "1") {
    cheVal = "1";
  }
  dma_condition.set("wrkPlCd", ed_wrkPlCd.getValue());
  dma_condition.set("mrn", ed_mrn.getValue());
  dma_condition.set("msn", ed_msn.getValue() == "" ? -1 : ed_msn.getValue());
  dma_condition.set("hsn", ed_hsn.getValue() == "" ? -1 : ed_hsn.getValue());
  dma_condition.set("blNo", ed_blNo.getValue());
  dma_condition.set("odrNo", ed_odrNo.getValue());
  dma_condition.set("preRetrieve", "0");
  dma_condition.set("crryinoutDtmFrom", crryinoutDtmFrom.getValue());
  dma_condition.set("crryinoutDtmTo", crryinoutDtmTo.getValue());

  //분할반출
  if (divsCrryinoutYn.getValue() == "1") {
    dma_condition.set("divsCrryinoutYn", "1");
  } else {
    dma_condition.set("divsCrryinoutYn", "0");
  }
  $c.sbm.execute($p, sbm_retrieve);
};

//전송
scwin.f_Save_0 = async function (val) {
  let k = 0;
  let sndClsCd = "0";

  //변경한 데이터가 있는지 체크한다. 
  if (ds_retrieve.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_001, ["Data"]);
    return;
  }

  // 필수항목 체크
  if (!(await $c.gus.cfValidate($p, [gr_retrieve], null, true))) {
    return;
  }
  if (await $c.win.confirm($p, "저장하시겠습니까?")) {
    for (i = 0; i < ds_retrieve.getRowCount(); i++) {
      if (ds_retrieve.getRowStatusValue(i) == 1) {
        //갱신
        if (ds_retrieve.getCellData(i, "che") == 1) {
          k++;
          if (ds_retrieve.getCellData(i, "crryinoutPatternCd") == "55" || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "70" || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "82" || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "90") {
            if (ds_retrieve.getCellData(i, "crryinoutBasisNo") != "") {
              await $c.win.alert($p, "현재 선택하신 반출유형은 반출근거번호가 필요없습니다.삭제해 주시길 바랍니다.");
              gr_retrieve.setFocusedCell(i, "crryinoutBasisNo", true);
              return;
            }
          } else {
            if (ds_retrieve.getCellData(i, "crryinoutPatternCd") == "") {
              await $c.win.alert($p, "반출유형코드는 필수항목입니다");
              gr_retrieve.setFocusedCell(i, "crryinoutPatternCd", true);
              return;
            }
          }
          sndClsCd = "0"; // 전송구분코드

          ds_retrieve.setCellData(i, "sndClsCd", sndClsCd);
        }
      } else if (ds_retrieve.getRowStatusValue(i) == 3) {
        //삭제
        if (ds_retrieve.getCellData(i, "che") == 1) k++;
      }
    }
    if (k == 0) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_056, ["항목"]);
      return;
    }
    $c.sbm.execute($p, sbm_save);
  }
};
